     1→/**
     2→ * FreeLang Runtime Value System
     3→ * 모든 런타임 값을 나타내는 tagged union 타입
     4→ */
     5→
     6→/**
     7→ * 런타임에서 사용되는 모든 값의 타입
     8→ * Discriminated Union 패턴 사용으로 타입 안전성 보장
     9→ */
    10→export type Value =
    11→  | { type: 'null' }
    12→  | { type: 'bool'; value: boolean }
    13→  | { type: 'int'; value: number }
    14→  | { type: 'float'; value: number }
    15→  | { type: 'string'; value: string }
    16→  | { type: 'array'; value: Value[] }
    17→  | { type: 'object'; value: Map<string, Value> }
    18→  | { type: 'function'; params: string[]; body: any }
    19→  | { type: 'builtin'; name: string; arity: number };
    20→
    21→/**
    22→ * Value 타입의 유틸리티 함수들
    23→ */
    24→export class ValueHandler {
    25→  /**
    26→   * Value를 문자열로 변환
    27→   */
    28→  static toString(v: Value): string {
    29→    switch (v.type) {
    30→      case 'null':
    31→        return 'null';
    32→      case 'bool':
    33→        return v.value ? 'true' : 'false';
    34→      case 'int':
    35→        return String(v.value);
    36→      case 'float':
    37→        return String(v.value);
    38→      case 'string':
    39→        return v.value;
    40→      case 'array':
    41→        return `[${v.value.map(item => this.toString(item)).join(', ')}]`;
    42→      case 'object':
    43→        const entries = Array.from(v.value.entries());
    44→        const pairs = entries.map(([k, val]) => `${k}: ${this.toString(val)}`);
    45→        return `{${pairs.join(', ')}}`;
    46→      case 'function':
    47→        return `<function(${v.params.join(', ')})>`;
    48→      case 'builtin':
    49→        return `<builtin: ${v.name}/${v.arity}>`;
    50→    }
    51→  }
    52→
    53→  /**
    54→   * Value를 숫자로 변환 (JavaScript 의미론)
    55→   */
    56→  static toNumber(v: Value): number {
    57→    switch (v.type) {
    58→      case 'null':
    59→        return 0;
    60→      case 'bool':
    61→        return v.value ? 1 : 0;
    62→      case 'int':
    63→      case 'float':
    64→        return v.value;
    65→      case 'string':
    66→        const n = parseFloat(v.value);
    67→        return isNaN(n) ? 0 : n;
    68→      case 'array':
    69→        return v.value.length; // 배열의 길이
    70→      case 'object':
    71→        return v.value.size; // 객체의 크기
    72→      default:
    73→        return 0;
    74→    }
    75→  }
    76→
    77→  /**
    78→   * Value를 불린으로 변환 (JavaScript truthy/falsy 의미론)
    79→   */
    80→  static toBoolean(v: Value): boolean {
    81→    switch (v.type) {
    82→      case 'null':
    83→        return false;
    84→      case 'bool':
    85→        return v.value;
    86→      case 'int':
    87→        return v.value !== 0;
    88→      case 'float':
    89→        return v.value !== 0.0;
    90→      case 'string':
    91→        return v.value.length > 0;
    92→      case 'array':
    93→        return v.value.length > 0;
    94→      case 'object':
    95→        return v.value.size > 0;
    96→      case 'function':
    97→      case 'builtin':
    98→        return true;
    99→    }
   100→  }
   101→
   102→  /**
   103→   * Value의 타입을 문자열로 반환
   104→   */
   105→  static typeOf(v: Value): string {
   106→    switch (v.type) {
   107→      case 'null':
   108→        return 'null';
   109→      case 'bool':
   110→        return 'bool';
   111→      case 'int':
   112→        return 'int';
   113→      case 'float':
   114→        return 'float';
   115→      case 'string':
   116→        return 'string';
   117→      case 'array':
   118→        return 'array';
   119→      case 'object':
   120→        return 'object';
   121→      case 'function':
   122→        return 'function';
   123→      case 'builtin':
   124→        return 'builtin';
   125→    }
   126→  }
   127→
   128→  /**
   129→   * Value의 길이를 반환 (string, array, object 타입)
   130→   */
   131→  static length(v: Value): number {
   132→    switch (v.type) {
   133→      case 'string':
   134→        return v.value.length;
   135→      case 'array':
   136→        return v.value.length;
   137→      case 'object':
   138→        return v.value.size;
   139→      default:
   140→        return 0;
   141→    }
   142→  }
   143→
   144→  /**
   145→   * 두 Value가 같은지 비교 (==)
   146→   */
   147→  static equals(a: Value, b: Value): boolean {
   148→    // 같은 타입끼리만 비교 (엄격한 비교)
   149→    if (a.type !== b.type) {
   150→      return false;
   151→    }
   152→
   153→    switch (a.type) {
   154→      case 'null':
   155→        return true;
   156→      case 'bool':
   157→        return a.value === (b as typeof a).value;
   158→      case 'int':
   159→      case 'float':
   160→        return a.value === (b as typeof a).value;
   161→      case 'string':
   162→        return a.value === (b as typeof a).value;
   163→      case 'array': {
   164→        const bArr = (b as typeof a).value;
   165→        if (a.value.length !== bArr.length) return false;
   166→        return a.value.every((v, i) => this.equals(v, bArr[i]));
   167→      }
   168→      case 'object': {
   169→        const bObj = (b as typeof a).value;
   170→        if (a.value.size !== bObj.size) return false;
   171→        for (const [k, v] of a.value) {
   172→          const bVal = bObj.get(k);
   173→          if (!bVal || !this.equals(v, bVal)) return false;
   174→        }
   175→        return true;
   176→      }
   177→      case 'function':
   178→        return false; // 함수는 참조로 비교 (추후 개선 가능)
   179→      case 'builtin':
   180→        return a.name === (b as typeof a).name;
   181→    }
   182→  }
   183→
   184→  /**
   185→   * 숫자 비교 (<)
   186→   */
   187→  static lessThan(a: Value, b: Value): boolean {
   188→    const aNum = this.toNumber(a);
   189→    const bNum = this.toNumber(b);
   190→    return aNum < bNum;
   191→  }
   192→
   193→  /**
   194→   * Value를 깊은 복사 (Deep Clone)
   195→   */
   196→  static clone(v: Value): Value {
   197→    switch (v.type) {
   198→      case 'null':
   199→      case 'bool':
   200→      case 'int':
   201→      case 'float':
   202→      case 'string':
   203→        return v;
   204→      case 'array':
   205→        return {
   206→          type: 'array',
   207→          value: v.value.map(item => this.clone(item)),
   208→        };
   209→      case 'object': {
   210→        const newMap = new Map<string, Value>();
   211→        for (const [k, val] of v.value) {
   212→          newMap.set(k, this.clone(val));
   213→        }
   214→        return {
   215→          type: 'object',
   216→          value: newMap,
   217→        };
   218→      }
   219→      case 'function':
   220→        return v; // 함수는 참조로 복사
   221→      case 'builtin':
   222→        return v;
   223→    }
   224→  }
   225→
   226→  /**
   227→   * Value를 JSON 호환 형식으로 변환
   228→   */
   229→  static toJSON(v: Value): any {
   230→    switch (v.type) {
   231→      case 'null':
   232→        return null;
   233→      case 'bool':
   234→        return v.value;
   235→      case 'int':
   236→      case 'float':
   237→        return v.value;
   238→      case 'string':
   239→        return v.value;
   240→      case 'array':
   241→        return v.value.map(item => this.toJSON(item));
   242→      case 'object': {
   243→        const obj: any = {};
   244→        for (const [k, val] of v.value) {
   245→          obj[k] = this.toJSON(val);
   246→        }
   247→        return obj;
   248→      }
   249→      case 'function':
   250→        return '[Function]';
   251→      case 'builtin':
   252→        return '[Builtin]';
   253→    }
   254→  }
   255→
   256→  /**
   257→   * JSON에서 Value로 변환
   258→   */
   259→  static fromJSON(obj: any): Value {
   260→    if (obj === null) {
   261→      return { type: 'null' };
   262→    }
   263→    if (typeof obj === 'boolean') {
   264→      return { type: 'bool', value: obj };
   265→    }
   266→    if (typeof obj === 'number') {
   267→      return Number.isInteger(obj)
   268→        ? { type: 'int', value: obj }
   269→        : { type: 'float', value: obj };
   270→    }
   271→    if (typeof obj === 'string') {
   272→      return { type: 'string', value: obj };
   273→    }
   274→    if (Array.isArray(obj)) {
   275→      return {
   276→        type: 'array',
   277→        value: obj.map(item => this.fromJSON(item)),
   278→      };
   279→    }
   280→    if (typeof obj === 'object') {
   281→      const map = new Map<string, Value>();
   282→      for (const [k, v] of Object.entries(obj)) {
   283→        map.set(k, this.fromJSON(v));
   284→      }
   285→      return { type: 'object', value: map };
   286→    }
   287→    return { type: 'null' };
   288→  }
   289→}
   290→
   291→/**
   292→ * 자주 사용되는 Value 상수들
   293→ */
   294→export const NULL: Value = { type: 'null' };
   295→export const TRUE: Value = { type: 'bool', value: true };
   296→export const FALSE: Value = { type: 'bool', value: false };
   297→
   298→/**
   299→ * Value를 생성하는 헬퍼 함수들
   300→ */
   301→export const Value = {
   302→  null: (): Value => ({ type: 'null' }),
   303→  bool: (b: boolean): Value => ({ type: 'bool', value: b }),
   304→  int: (n: number): Value => ({ type: 'int', value: Math.floor(n) }),
   305→  float: (n: number): Value => ({ type: 'float', value: n }),
   306→  string: (s: string): Value => ({ type: 'string', value: s }),
   307→  array: (arr: Value[]): Value => ({ type: 'array', value: arr }),
   308→  object: (obj: Map<string, Value>): Value => ({
   309→    type: 'object',
   310→    value: obj,
   311→  }),
   312→  function: (params: string[], body: any): Value => ({
   313→    type: 'function',
   314→    params,
   315→    body,
   316→  }),
   317→  builtin: (name: string, arity: number): Value => ({
   318→    type: 'builtin',
   319→    name,
   320→    arity,
   321→  }),
   322→};
   323→

