     1→/**
     2→ * Concurrency Functions - Cooperative Actor Model
     3→ * 타입 정의
     4→ */
     5→
     6→/**
     7→ * Actor 상태
     8→ */
     9→export enum ActorState {
    10→  CREATED = 'created',
    11→  RUNNING = 'running',
    12→  SUSPENDED = 'suspended',
    13→  COMPLETED = 'completed',
    14→  FAILED = 'failed'
    15→}
    16→
    17→/**
    18→ * Channel 메시지
    19→ */
    20→export interface Message<T = any> {
    21→  id: string;
    22→  data: T;
    23→  timestamp: number;
    24→  sender?: string;
    25→}
    26→
    27→/**
    28→ * Channel 상태
    29→ */
    30→export enum ChannelState {
    31→  OPEN = 'open',
    32→  CLOSED = 'closed',
    33→  DRAINED = 'drained'
    34→}
    35→
    36→/**
    37→ * Actor (경량 스레드)
    38→ */
    39→export interface Actor<T = any> {
    40→  id: string;
    41→  state: ActorState;
    42→  fn: (...args: any[]) => Promise<T>;
    43→  result?: T;
    44→  error?: Error;
    45→  startTime: number;
    46→  executedInstructions: number; // Instruction Slicing
    47→  lastYieldTime: number;
    48→}
    49→
    50→/**
    51→ * Channel (메시지 통로)
    52→ */
    53→export interface Channel<T = any> {
    54→  name: string;
    55→  state: ChannelState;
    56→  send(msg: T, sender?: string): Promise<void>;
    57→  recv(): Promise<Message<T>>;
    58→  close(): void;
    59→  isClosed(): boolean;
    60→  buffer(): Message<T>[];
    61→}
    62→
    63→/**
    64→ * Select 선택지
    65→ */
    66→export interface SelectCase<T = any> {
    67→  channel: Channel<T>;
    68→  handler: (msg: Message<T>) => Promise<void> | void;
    69→  timeout?: number;
    70→}
    71→
    72→/**
    73→ * Wait 결과
    74→ */
    75→export interface WaitResult<T = any> {
    76→  completed: T[];
    77→  failed: Error[];
    78→  cancelled: string[];
    79→  timeout: boolean;
    80→}
    81→
    82→/**
    83→ * 동시성 메트릭
    84→ */
    85→export interface ConcurrencyMetrics {
    86→  activeActors: number;
    87→  totalActorsCreated: number;
    88→  totalMessagesProcessed: number;
    89→  averageActorLifetime: number;
    90→  deadlockDetections: number;
    91→  instructionSliceSize: number;
    92→  yieldFrequency: number;
    93→}
    94→
    95→/**
    96→ * 협동적 Actor 모델 설정
    97→ */
    98→export interface CooperativeActorConfig {
    99→  instructionSliceSize: number; // 명령어 개수 (default: 1000)
   100→  yieldTimeMs: number; // Yield 시간 (default: 0)
   101→  deadlockTimeout: number; // 데드락 감지 시간 (default: 30000)
   102→  channelBufferSize: number; // 채널 버퍼 크기 (default: 100)
   103→  enableInstructionCounting: boolean; // 명령어 계산 활성화
   104→  enableDeadlockDetection: boolean; // 데드락 감지 활성화
   105→}
   106→
   107→/**
   108→ * Concurrency 런타임
   109→ */
   110→export interface ConcurrencyRuntime {
   111→  spawn<T>(fn: (...args: any[]) => Promise<T>, ...args: any[]): Promise<Actor<T>>;
   112→  channel<T>(name: string): Channel<T>;
   113→  select<T>(cases: SelectCase<T>[], timeout?: number): Promise<T>;
   114→  wait<T>(actors: Actor<T>[]): Promise<WaitResult<T>>;
   115→  sleep(ms: number): Promise<void>;
   116→  metrics(): ConcurrencyMetrics;
   117→}
   118→

