     1→/**
     2→ * FreeLang v4 StdLib — 공통 Value 타입
     3→ *
     4→ * FreeLang v4 VM과 동일한 Value 구조 (자체 정의 — 외부 의존 없음)
     5→ */
     6→
     7→export type Value =
     8→  | { tag: "i32";    val: number }
     9→  | { tag: "f64";    val: number }
    10→  | { tag: "str";    val: string }
    11→  | { tag: "bool";   val: boolean }
    12→  | { tag: "arr";    elements: Value[] }
    13→  | { tag: "struct"; fields: Map<string, Value> }
    14→  | { tag: "ok";     val: Value }
    15→  | { tag: "err";    val: string }
    16→  | { tag: "some";   val: Value }
    17→  | { tag: "none" }
    18→  | { tag: "void" };
    19→
    20→// ── 생성 헬퍼 ────────────────────────────────────────────────
    21→
    22→export const V = {
    23→  i32:    (n: number):     Value => ({ tag: "i32", val: Math.trunc(n) }),
    24→  f64:    (n: number):     Value => ({ tag: "f64", val: n }),
    25→  str:    (s: string):     Value => ({ tag: "str", val: s }),
    26→  bool:   (b: boolean):    Value => ({ tag: "bool", val: b }),
    27→  arr:    (els: Value[]):  Value => ({ tag: "arr", elements: els }),
    28→  ok:     (v: Value):      Value => ({ tag: "ok", val: v }),
    29→  err:    (msg: string):   Value => ({ tag: "err", val: msg }),
    30→  some:   (v: Value):      Value => ({ tag: "some", val: v }),
    31→  none:   ():              Value => ({ tag: "none" }),
    32→  void_:  ():              Value => ({ tag: "void" }),
    33→  struct: (fields: Record<string, Value> | Map<string, Value>): Value => ({
    34→    tag:    "struct",
    35→    fields: fields instanceof Map ? fields : new Map(Object.entries(fields)),
    36→  }),
    37→};
    38→
    39→// ── 타입 단언 헬퍼 ───────────────────────────────────────────
    40→
    41→export function assertStr(v: Value, fn: string): string {
    42→  if (v.tag !== "str") throw new TypeError(`${fn}: str 필요 (got ${v.tag})`);
    43→  return (v as Extract<Value, { tag: "str" }>).val;
    44→}
    45→export function assertI32(v: Value, fn: string): number {
    46→  if (v.tag !== "i32") throw new TypeError(`${fn}: i32 필요 (got ${v.tag})`);
    47→  return (v as Extract<Value, { tag: "i32" }>).val;
    48→}
    49→export function assertBool(v: Value, fn: string): boolean {
    50→  if (v.tag !== "bool") throw new TypeError(`${fn}: bool 필요 (got ${v.tag})`);
    51→  return (v as Extract<Value, { tag: "bool" }>).val;
    52→}
    53→export function assertArr(v: Value, fn: string): Value[] {
    54→  if (v.tag !== "arr") throw new TypeError(`${fn}: arr 필요 (got ${v.tag})`);
    55→  return (v as Extract<Value, { tag: "arr" }>).elements;
    56→}
    57→

