     1→/**
     2→ * FreeLang v4 StdLib — Functional Programming (4개 + 확장)
     3→ *
     4→ * 1. compose(...fns)         → (x) → y      우→좌 함수 합성
     5→ * 2. curry(fn, arity)        → curried fn   커링 (인자 개수 지정)
     6→ * 3. memoize(fn)             → fn           메모이제이션 (순수 함수 캐싱)
     7→ * 4. partial(fn, ...args)    → fn           부분 적용
     8→ *
     9→ * + pipe(...fns)             좌→우 합성
    10→ * + once(fn)                 최초 1회만 실행
    11→ * + throttle(fn, ms)         스로틀링
    12→ * + flip(fn)                 인수 순서 뒤집기
    13→ */
    14→
    15→import { Value } from "./types";
    16→
    17→// FreeLang Value를 받아 Value를 반환하는 함수 타입
    18→export type FlFn = (...args: Value[]) => Value;
    19→
    20→// ============================================================
    21→// 1. compose — 우→좌 합성  compose(f, g)(x) = f(g(x))
    22→// ============================================================
    23→
    24→export function compose(...fns: FlFn[]): FlFn {
    25→  if (fns.length === 0) throw new Error("compose: 함수가 1개 이상 필요합니다");
    26→  return (...args: Value[]): Value => {
    27→    const reversed = [...fns].reverse();
    28→    let result: Value = reversed[0](...args);
    29→    for (let i = 1; i < reversed.length; i++) {
    30→      result = reversed[i](result);
    31→    }
    32→    return result;
    33→  };
    34→}
    35→
    36→// ============================================================
    37→// 2. pipe — 좌→우 합성  pipe(f, g)(x) = g(f(x))
    38→// ============================================================
    39→
    40→export function pipe(...fns: FlFn[]): FlFn {
    41→  if (fns.length === 0) throw new Error("pipe: 함수가 1개 이상 필요합니다");
    42→  return (...args: Value[]): Value => {
    43→    let result: Value = fns[0](...args);
    44→    for (let i = 1; i < fns.length; i++) {
    45→      result = fns[i](result);
    46→    }
    47→    return result;
    48→  };
    49→}
    50→
    51→// ============================================================
    52→// 3. curry — 커링 (arity개 인수를 하나씩 받음)
    53→// ============================================================
    54→
    55→export function curry(fn: FlFn, arity: number): FlFn {
    56→  if (arity <= 0) throw new RangeError("curry: arity는 1 이상이어야 합니다");
    57→
    58→  function curried(collected: Value[]): FlFn {
    59→    return (...args: Value[]): Value => {
    60→      const next = [...collected, ...args];
    61→      if (next.length >= arity) {
    62→        return fn(...next.slice(0, arity));
    63→      }
    64→      return curried(next) as unknown as Value; // 타입 편의상 캐스팅
    65→    };
    66→  }
    67→
    68→  return curried([]);
    69→}
    70→
    71→// ============================================================
    72→// 4. memoize — 순수 함수 결과 캐싱 (인수는 JSON 직렬화)
    73→// ============================================================
    74→
    75→export function memoize(fn: FlFn): FlFn {
    76→  const cache = new Map<string, Value>();
    77→  return (...args: Value[]): Value => {
    78→    const key = JSON.stringify(args, (_k, v) => {
    79→      // Map은 배열로 직렬화
    80→      if (v instanceof Map) return Object.fromEntries(v);
    81→      return v;
    82→    });
    83→    if (cache.has(key)) return cache.get(key)!;
    84→    const result = fn(...args);
    85→    cache.set(key, result);
    86→    return result;
    87→  };
    88→}
    89→
    90→/** 캐시 히트 수를 추적하는 memoize (테스트용) */
    91→export function memoize_tracked(fn: FlFn): { fn: FlFn; hits: () => number; misses: () => number } {
    92→  const cache = new Map<string, Value>();
    93→  let hits = 0, misses = 0;
    94→  const wrapped: FlFn = (...args: Value[]): Value => {
    95→    const key = JSON.stringify(args, (_k, v) => (v instanceof Map ? Object.fromEntries(v) : v));
    96→    if (cache.has(key)) { hits++; return cache.get(key)!; }
    97→    misses++;
    98→    const result = fn(...args);
    99→    cache.set(key, result);
   100→    return result;
   101→  };
   102→  return { fn: wrapped, hits: () => hits, misses: () => misses };
   103→}
   104→
   105→// ============================================================
   106→// 5. partial — 부분 적용  partial(f, a, b)(c) = f(a, b, c)
   107→// ============================================================
   108→
   109→export function partial(fn: FlFn, ...partialArgs: Value[]): FlFn {
   110→  return (...remainingArgs: Value[]): Value => fn(...partialArgs, ...remainingArgs);
   111→}
   112→
   113→// ============================================================
   114→// 6. once — 최초 1회만 실행, 이후 첫 번째 결과 반환
   115→// ============================================================
   116→
   117→export function once(fn: FlFn): FlFn {
   118→  let called = false;
   119→  let result: Value | null = null;
   120→  return (...args: Value[]): Value => {
   121→    if (!called) {
   122→      called = true;
   123→      result = fn(...args);
   124→    }
   125→    return result!;
   126→  };
   127→}
   128→
   129→// ============================================================
   130→// 7. flip — 인수 첫 두 개 순서 뒤집기
   131→// ============================================================
   132→
   133→export function flip(fn: FlFn): FlFn {
   134→  return (...args: Value[]): Value => {
   135→    if (args.length < 2) return fn(...args);
   136→    const [a, b, ...rest] = args;
   137→    return fn(b, a, ...rest);
   138→  };
   139→}
   140→
   141→// ============================================================
   142→// 8. identity — 항등 함수
   143→// ============================================================
   144→
   145→export function identity(x: Value): Value {
   146→  return x;
   147→}
   148→
   149→// ============================================================
   150→// 9. constant — 상수 함수
   151→// ============================================================
   152→
   153→export function constant(x: Value): FlFn {
   154→  return () => x;
   155→}
