     1→/**
     2→ * FreeLang v4 StdLib — Database Functions (4개 + 확장)
     3→ *
     4→ * 인메모리 관계형 DB 시뮬레이션 (실제 DB 드라이버 없이 동작)
     5→ *
     6→ * 1. db_query(db, sql, params)    → ok(arr[struct]) | err
     7→ *    - SELECT 지원: WHERE, ORDER BY, LIMIT, OFFSET
     8→ *    - 파라미터 바인딩: $1, $2, ... 형식
     9→ *
    10→ * 2. db_insert(db, table, row)    → ok(i32) | err  (삽입된 row id)
    11→ *
    12→ * 3. db_update(db, table, set, where) → ok(i32) | err  (변경된 row 수)
    13→ *
    14→ * 4. db_delete(db, table, where)  → ok(i32) | err  (삭제된 row 수)
    15→ *
    16→ * + db_create(name)         → Database 인스턴스 생성
    17→ * + db_create_table(db, table, schema)
    18→ * + db_count(db, table, where)    → i32
    19→ * + db_transaction(db, fn)        → ok | err
    20→ */
    21→
    22→import { Value, V, assertStr, assertI32 } from "./types";
    23→
    24→// ============================================================
    25→// 내부 타입
    26→// ============================================================
    27→
    28→type Row = Map<string, Value>;
    29→
    30→interface Table {
    31→  name:    string;
    32→  schema:  Map<string, string>;  // col → type
    33→  rows:    Row[];
    34→  nextId:  number;
    35→}
    36→
    37→export interface Database {
    38→  name:    string;
    39→  tables:  Map<string, Table>;
    40→  txActive: boolean;
    41→  txLog:   { op: string; table: string; data: unknown }[];
    42→}
    43→
    44→// ============================================================
    45→// DB 생성
    46→// ============================================================
    47→
    48→export function db_create(name: string): Database {
    49→  return { name, tables: new Map(), txActive: false, txLog: [] };
    50→}
    51→
    52→export function db_create_table(
    53→  db:     Database,
    54→  table:  string,
    55→  schema: Record<string, string>
    56→): void {
    57→  if (db.tables.has(table)) throw new Error(`db_create_table: 테이블 '${table}' 이미 존재`);
    58→  db.tables.set(table, {
    59→    name:   table,
    60→    schema: new Map(Object.entries(schema)),
    61→    rows:   [],
    62→    nextId: 1,
    63→  });
    64→}
    65→
    66→// ============================================================
    67→// 1. db_query
    68→// ============================================================
    69→
    70→/**
    71→ * 지원 쿼리:
    72→ *   SELECT * FROM table
    73→ *   SELECT col1, col2 FROM table WHERE col = $1
    74→ *   SELECT * FROM table ORDER BY col ASC|DESC
    75→ *   SELECT * FROM table LIMIT $1 OFFSET $2
    76→ */
    77→export function db_query(
    78→  db:     Database,
    79→  sql:    string,
    80→  params: Value[] = []
    81→): Value {
    82→  try {
    83→    const result = executeSelect(db, sql.trim(), params);
    84→    return V.ok(V.arr(result.map(rowToStruct)));
    85→  } catch (e: any) {
    86→    return V.err(`db_query: ${e.message}`);
    87→  }
    88→}
    89→
    90→function executeSelect(db: Database, sql: string, params: Value[]): Row[] {
    91→  // 파라미터 바인딩 ($1, $2, ...)
    92→  const bound = sql.replace(/\$(\d+)/g, (_, n) => {
    93→    const idx = parseInt(n, 10) - 1;
    94→    const v   = params[idx];
    95→    if (!v) throw new Error(`파라미터 $${n} 없음`);
    96→    return valueToSql(v);
    97→  });
    98→
    99→  // 파싱
   100→  const upper = bound.toUpperCase();
   101→  if (!upper.startsWith("SELECT")) throw new Error("SELECT만 지원합니다");
   102→
   103→  // FROM 절 추출
   104→  const fromMatch = /FROM\s+(\w+)/i.exec(bound);
   105→  if (!fromMatch) throw new Error("FROM 절 없음");
   106→  const tableName = fromMatch[1];
   107→  const table     = db.tables.get(tableName);
   108→  if (!table) throw new Error(`테이블 '${tableName}' 없음`);
   109→
   110→  let rows = [...table.rows];
   111→
   112→  // WHERE 절
   113→  const whereMatch = /WHERE\s+(.+?)(?:\s+ORDER|\s+LIMIT|\s+OFFSET|$)/i.exec(bound);
   114→  if (whereMatch) {
   115→    rows = rows.filter((row) => evalWhere(row, whereMatch[1].trim()));
   116→  }
   117→
   118→  // ORDER BY 절
   119→  const orderMatch = /ORDER\s+BY\s+(\w+)(?:\s+(ASC|DESC))?/i.exec(bound);
   120→  if (orderMatch) {
   121→    const col = orderMatch[1];
   122→    const dir = (orderMatch[2] ?? "ASC").toUpperCase();
   123→    rows.sort((a, b) => {
   124→      const av = a.get(col), bv = b.get(col);
   125→      const an = toComparable(av), bn = toComparable(bv);
   126→      return dir === "ASC" ? (an < bn ? -1 : an > bn ? 1 : 0) : (an > bn ? -1 : an < bn ? 1 : 0);
   127→    });
   128→  }
   129→
   130→  // LIMIT / OFFSET
   131→  const limitMatch  = /LIMIT\s+(\d+)/i.exec(bound);
   132→  const offsetMatch = /OFFSET\s+(\d+)/i.exec(bound);
   133→  const offset = offsetMatch ? parseInt(offsetMatch[1], 10) : 0;
   134→  const limit  = limitMatch  ? parseInt(limitMatch[1], 10)  : rows.length;
   135→  rows = rows.slice(offset, offset + limit);
   136→
   137→  // SELECT 컬럼 필터
   138→  const colPart = /SELECT\s+(.+?)\s+FROM/i.exec(bound)?.[1] ?? "*";
   139→  if (colPart.trim() !== "*") {
   140→    const cols = colPart.split(",").map((c) => c.trim());
   141→    rows = rows.map((row) => {
   142→      const filtered = new Map<string, Value>();
   143→      for (const col of cols) {
   144→        if (row.has(col)) filtered.set(col, row.get(col)!);
   145→      }
   146→      return filtered;
   147→    });
   148→  }
   149→
   150→  return rows;
   151→}
   152→
   153→function evalWhere(row: Row, expr: string): boolean {
   154→  // 지원: col = 'val', col = 123, col > 123, col < 123, col >= 123, col <= 123, col != 'val'
   155→  const opMatch = /(\w+)\s*(=|!=|>=|<=|>|<)\s*('[^']*'|\d+\.?\d*)/i.exec(expr);
   156→  if (!opMatch) return true;
   157→  const [, col, op, rawVal] = opMatch;
   158→  const rowVal = row.get(col);
   159→  if (!rowVal) return false;
   160→
   161→  const expected: Value = rawVal.startsWith("'")
   162→    ? V.str(rawVal.slice(1, -1))
   163→    : rawVal.includes(".")
   164→      ? V.f64(parseFloat(rawVal))
   165→      : V.i32(parseInt(rawVal, 10));
   166→
   167→  const a = toComparable(rowVal);
   168→  const b = toComparable(expected);
   169→
   170→  switch (op) {
   171→    case "=":  return a === b;
   172→    case "!=": return a !== b;
   173→    case ">":  return a  > b;
   174→    case "<":  return a  < b;
   175→    case ">=": return a >= b;
   176→    case "<=": return a <= b;
   177→  }
   178→  return false;
   179→}
   180→
   181→function toComparable(v: Value | undefined): string | number {
   182→  if (!v) return "";
   183→  if (v.tag === "i32" || v.tag === "f64") return (v as any).val;
   184→  if (v.tag === "str") return (v as any).val;
   185→  if (v.tag === "bool") return (v as any).val ? 1 : 0;
   186→  return "";
   187→}
   188→
   189→function valueToSql(v: Value): string {
   190→  if (v.tag === "str") return `'${(v as any).val}'`;
   191→  if (v.tag === "i32" || v.tag === "f64") return String((v as any).val);
   192→  if (v.tag === "bool") return (v as any).val ? "1" : "0";
   193→  return "NULL";
   194→}
   195→
   196→function rowToStruct(row: Row): Value {
   197→  return { tag: "struct", fields: new Map(row) };
   198→}
   199→
   200→// ============================================================
   201→// 2. db_insert
   202→// ============================================================
   203→
   204→export function db_insert(db: Database, tableName: string, rowData: Record<string, Value>): Value {
   205→  const table = db.tables.get(tableName);
   206→  if (!table) return V.err(`db_insert: 테이블 '${tableName}' 없음`);
   207→
   208→  const id  = table.nextId++;
   209→  const row = new Map<string, Value>([["id", V.i32(id)], ...Object.entries(rowData)]);
   210→  table.rows.push(row);
   211→
   212→  if (db.txActive) db.txLog.push({ op: "insert", table: tableName, data: id });
   213→
   214→  return V.ok(V.i32(id));
   215→}
   216→
   217→// ============================================================
   218→// 3. db_update
   219→// ============================================================
   220→
   221→/**
   222→ * @param set   { col: newValue, ... }
   223→ * @param where 조건 문자열 "col = 'val'" 형식
   224→ */
   225→export function db_update(
   226→  db:        Database,
   227→  tableName: string,
   228→  setData:   Record<string, Value>,
   229→  where:     string
   230→): Value {
   231→  const table = db.tables.get(tableName);
   232→  if (!table) return V.err(`db_update: 테이블 '${tableName}' 없음`);
   233→
   234→  let count = 0;
   235→  for (const row of table.rows) {
   236→    if (evalWhere(row, where)) {
   237→      for (const [col, val] of Object.entries(setData)) {
   238→        row.set(col, val);
   239→      }
   240→      count++;
   241→    }
   242→  }
   243→
   244→  if (db.txActive) db.txLog.push({ op: "update", table: tableName, data: count });
   245→  return V.ok(V.i32(count));
   246→}
   247→
   248→// ============================================================
   249→// 4. db_delete
   250→// ============================================================
   251→
   252→export function db_delete(
   253→  db:        Database,
   254→  tableName: string,
   255→  where:     string
   256→): Value {
   257→  const table = db.tables.get(tableName);
   258→  if (!table) return V.err(`db_delete: 테이블 '${tableName}' 없음`);
   259→
   260→  const before = table.rows.length;
   261→  table.rows = table.rows.filter((row) => !evalWhere(row, where));
   262→  const deleted = before - table.rows.length;
   263→
   264→  if (db.txActive) db.txLog.push({ op: "delete", table: tableName, data: deleted });
   265→  return V.ok(V.i32(deleted));
   266→}
   267→
   268→// ============================================================
   269→// 5. db_count
   270→// ============================================================
   271→
   272→export function db_count(db: Database, tableName: string, where = ""): Value {
   273→  const table = db.tables.get(tableName);
   274→  if (!table) return V.err(`db_count: 테이블 '${tableName}' 없음`);
   275→
   276→  const count = where
   277→    ? table.rows.filter((row) => evalWhere(row, where)).length
   278→    : table.rows.length;
   279→
   280→  return V.i32(count);
   281→}
   282→
   283→// ============================================================
   284→// 6. 트랜잭션
   285→// ============================================================
   286→
   287→export function db_begin(db: Database): void {
   288→  db.txActive = true;
   289→  db.txLog    = [];
   290→}
   291→
   292→export function db_commit(db: Database): Value {
   293→  db.txActive = false;
   294→  const ops = db.txLog.length;
   295→  db.txLog   = [];
   296→  return V.ok(V.i32(ops));
   297→}
   298→
   299→export function db_rollback(db: Database): Value {
   300→  // 간소화: 실제 rollback은 log를 역순으로 되돌림 (여기서는 txActive 해제만)
   301→  db.txActive = false;
   302→  const ops = db.txLog.length;
   303→  db.txLog   = [];
   304→  return V.ok(V.i32(ops));
   305→}
