     2→ * FreeLang Virtual Machine
     3→ * 스택 기반의 간단한 인터프리터
     4→ */
     5→
     6→import { Value, ValueHandler } from './value';
     7→import { Instruction, OpcodeType } from './bytecode';
     8→
     9→/**
    10→ * 함수 호출 프레임
    11→ */
    12→interface Frame {
    13→  name: string;
    14→  returnAddr: number;
    15→  localVariables: Map<number, Value>;
    16→}
    17→
    18→/**
    19→ * 런타임 에러
    20→ */
    21→export class RuntimeError extends Error {
    22→  constructor(
    23→    message: string,
    24→    public line: number = 0,
    25→    public column: number = 0
    26→  ) {
    27→    super(message);
    28→    this.name = 'RuntimeError';
    29→  }
    30→}
    31→
    32→/**
    33→ * FreeLang Virtual Machine
    34→ */
    35→export class VirtualMachine {
    36→  private stack: Value[] = [];
    37→  private memory: Map<number, Value> = new Map(); // 힙 메모리
    38→  private globals: Map<string, Value> = new Map(); // 전역 변수
    39→  private locals: Map<number, Value> = new Map(); // 지역 변수
    40→  private callStack: Frame[] = [];
    41→  private pc: number = 0; // 프로그램 카운터
    42→  private instructions: Instruction[] = [];
    43→  private builtins: Map<string, Function> = new Map();
    44→  private nextPtr: number = 0; // 메모리 포인터
    45→
    46→  constructor() {
    47→    this.registerBuiltins();
    48→  }
    49→
    50→  /**
    51→   * 표준 내장 함수 등록
    52→   */
    53→  private registerBuiltins(): void {
    54→    // 나중에 stdlib 모듈에서 자동으로 등록됨
    55→  }
    56→
    57→  /**
    58→   * Bytecode 실행
    59→   */
    60→  public execute(instructions: Instruction[]): Value {
    61→    this.instructions = instructions;
    62→    this.pc = 0;
    63→    this.stack = [];
    64→
    65→    try {
    66→      while (this.pc < instructions.length) {
    67→        const instr = instructions[this.pc];
    68→        this.executeInstruction(instr);
    69→        this.pc++;
    70→      }
    71→      return this.stack.pop() || { type: 'null' };
    72→    } catch (error) {
    73→      if (error instanceof RuntimeError) {
    74→        throw error;
    75→      }
    76→      throw new RuntimeError(
    77→        `VM Error: ${error instanceof Error ? error.message : String(error)}`,
    78→        instructions[this.pc]?.line || 0,
    79→        instructions[this.pc]?.column || 0
    80→      );
    81→    }
    82→  }
    83→
    84→  /**
    85→   * 개별 명령어 실행
    86→   */
    87→  private executeInstruction(instr: Instruction): void {
    88→    switch (instr.op) {
    89→      case OpcodeType.PUSH:
    90→        this.stack.push(instr.arg);
    91→        break;
    92→
    93→      case OpcodeType.POP:
    94→        if (this.stack.length === 0) {
    95→          throw new RuntimeError('Stack underflow');
    96→        }
    97→        this.stack.pop();
    98→        break;
    99→
   100→      case OpcodeType.DUP:

