   100→      case OpcodeType.DUP:
   101→        if (this.stack.length === 0) {
   102→          throw new RuntimeError('Stack underflow');
   103→        }
   104→        const top = this.stack[this.stack.length - 1];
   105→        this.stack.push(ValueHandler.clone(top));
