   112→
   113→      case OpcodeType.SUB:
   114→        this.binaryOp((a, b) => a - b, instr);
   115→        break;
   116→
   117→      case OpcodeType.MUL:
   118→        this.binaryOp((a, b) => a * b, instr);
   119→        break;
   120→
   121→      case OpcodeType.DIV:
   122→        this.binaryOp((a, b) => {
   123→          if (b === 0) throw new RuntimeError('Division by zero');
   124→          return a / b;
   125→        }, instr);
   126→        break;
   127→
   128→      case OpcodeType.MOD:
   129→        this.binaryOp((a, b) => {
   130→          if (b === 0) throw new RuntimeError('Division by zero');
   131→          return a % b;
   132→        }, instr);
   133→        break;
   134→
   135→      // 비교 연산
   136→      case OpcodeType.EQ: {
   137→        const b = this.popValue(instr);
   138→        const a = this.popValue(instr);
   139→        const result = ValueHandler.equals(a, b);
   140→        this.stack.push({ type: 'bool', value: result });
   141→        break;
   142→      }
   143→
   144→      case OpcodeType.NE: {
   145→        const b = this.popValue(instr);
   146→        const a = this.popValue(instr);
   147→        const result = !ValueHandler.equals(a, b);
   148→        this.stack.push({ type: 'bool', value: result });
   149→        break;
   150→      }
   151→
   152→      case OpcodeType.LT: {
   153→        const b = this.popValue(instr);
   154→        const a = this.popValue(instr);
   155→        const result = ValueHandler.lessThan(a, b);
   156→        this.stack.push({ type: 'bool', value: result });
   157→        break;
   158→      }
   159→
   160→      case OpcodeType.LTE: {
   161→        const b = this.popValue(instr);
   162→        const a = this.popValue(instr);
   163→        const result =
   164→          ValueHandler.lessThan(a, b) || ValueHandler.equals(a, b);
   165→        this.stack.push({ type: 'bool', value: result });
   166→        break;
   167→      }
   168→
   169→      case OpcodeType.GT: {
   170→        const b = this.popValue(instr);
   171→        const a = this.popValue(instr);
   172→        const result = ValueHandler.lessThan(b, a);
   173→        this.stack.push({ type: 'bool', value: result });
   174→        break;
   175→      }
   176→
   177→      case OpcodeType.GTE: {
   178→        const b = this.popValue(instr);
   179→        const a = this.popValue(instr);
   180→        const result =
   181→          ValueHandler.lessThan(b, a) || ValueHandler.equals(a, b);
   182→        this.stack.push({ type: 'bool', value: result });
   183→        break;
   184→      }
   185→
   186→      // 논리 연산
   187→      case OpcodeType.AND: {
   188→        const b = this.popValue(instr);
   189→        const a = this.popValue(instr);
   190→        const result =
   191→          ValueHandler.toBoolean(a) && ValueHandler.toBoolean(b);
   192→        this.stack.push({ type: 'bool', value: result });
   193→        break;
   194→      }
   195→
   196→      case OpcodeType.OR: {
   197→        const b = this.popValue(instr);
   198→        const a = this.popValue(instr);
   199→        const result =
   200→          ValueHandler.toBoolean(a) || ValueHandler.toBoolean(b);
   201→        this.stack.push({ type: 'bool', value: result });
   202→        break;
   203→      }
   204→
   205→      case OpcodeType.NOT: {
   206→        const a = this.popValue(instr);
   207→        const result = !ValueHandler.toBoolean(a);
   208→        this.stack.push({ type: 'bool', value: result });
   209→        break;
   210→      }
   211→
   212→      // 제어 흐름
   213→      case OpcodeType.JUMP:
   214→        this.pc = instr.arg - 1; // -1은 pc++이 되기 때문
   215→        break;
   216→
   217→      case OpcodeType.JUMP_IF_TRUE: {
   218→        const cond = this.popValue(instr);
   219→        if (ValueHandler.toBoolean(cond)) {
   220→          this.pc = instr.arg - 1;
   221→        }
   222→        break;
   223→      }
   224→
   225→      case OpcodeType.JUMP_IF_FALSE: {
   226→        const cond = this.popValue(instr);
   227→        if (!ValueHandler.toBoolean(cond)) {
   228→          this.pc = instr.arg - 1;
   229→        }
   230→        break;
   231→      }
   232→
   233→      // 변수 접근
   234→      case OpcodeType.LOAD_LOCAL: {
   235→        const index = instr.arg;
   236→        const value = this.locals.get(index) || { type: 'null' };
   237→        this.stack.push(value);
   238→        break;
   239→      }
   240→
   241→      case OpcodeType.STORE_LOCAL: {
   242→        const index = instr.arg;
   243→        const value = this.popValue(instr);
   244→        this.locals.set(index, value);
   245→        break;
   246→      }
   247→
   248→      case OpcodeType.LOAD_GLOBAL: {
   249→        const name = instr.arg;
   250→        const value = this.globals.get(name) || { type: 'null' };
   251→        this.stack.push(value);
   252→        break;
   253→      }
   254→
   255→      case OpcodeType.STORE_GLOBAL: {
   256→        const name = instr.arg;
   257→        const value = this.popValue(instr);
   258→        this.globals.set(name, value);
   259→        break;
   260→      }
   261→
   262→      case OpcodeType.PRINT: {
   263→        const value = this.popValue(instr);
   264→        process.stdout.write(ValueHandler.toString(value));
   265→        break;
   266→      }
   267→
   268→      case OpcodeType.HALT:
   269→        this.pc = this.instructions.length; // 프로그램 종료
   270→        break;
   271→
   272→      case OpcodeType.NOP:
   273→        // No operation
   274→        break;
   275→
   276→      default:
   277→        throw new RuntimeError(`Unknown opcode: ${instr.op}`);
   278→    }
   279→  }
   280→
   281→  /**
   282→   * 이진 연산 수행
   283→   */
   284→  private binaryOp(
   285→    op: (a: number, b: number) => number,
   286→    instr: Instruction
   287→  ): void {
   288→    const b = this.popNumber(instr);
   289→    const a = this.popNumber(instr);
   290→    const result = op(a, b);
   291→
   292→    // 결과 타입 결정 (정수인지 실수인지)
   293→    const isInt = Number.isInteger(result);
   294→    this.stack.push(
   295→      isInt ? { type: 'int', value: result } : { type: 'float', value: result }
   296→    );
   297→  }
