   760→      // Advanced Strings (3)
   761→      case "starts_with": {
   762→        if (args[0].tag === "str" && args[1].tag === "str") {
   763→          const result = args[0].val.startsWith(args[1].val);
   764→          return { tag: "bool", val: result };
   765→        }
   766→        return { tag: "bool", val: false };
   767→      }
   768→      case "ends_with": {
   769→        if (args[0].tag === "str" && args[1].tag === "str") {
   770→          const result = args[0].val.endsWith(args[1].val);
   771→          return { tag: "bool", val: result };
   772→        }
   773→        return { tag: "bool", val: false };
   774→      }
   775→      case "replace": {
   776→        if (args[0].tag === "str" && args[1].tag === "str" && args[2].tag === "str") {
   777→          const result = args[0].val.replaceAll(args[1].val, args[2].val);
   778→          return { tag: "str", val: result };
   779→        }
   780→        return args[0];
   781→      }
   782→
   783→      // Advanced Arrays (3)
   784→      case "reverse": {
   785→        if (args[0].tag === "arr") {
   786→          const reversed = [...args[0].val].reverse();
   787→          return { tag: "arr", val: reversed };
   788→        }
   789→        return args[0];
   790→      }
   791→      case "sort": {
   792→        if (args[0].tag === "arr") {
   793→          const sorted = [...args[0].val].sort((a, b) => {
   794→            const aVal = (a as any).val ?? 0;
   795→            const bVal = (b as any).val ?? 0;
   796→            return aVal < bVal ? -1 : aVal > bVal ? 1 : 0;
   797→          });
   798→          return { tag: "arr", val: sorted };
   799→        }
   800→        return args[0];
   801→      }
   802→      case "unique": {
   803→        if (args[0].tag === "arr") {
   804→          const seen = new Set<string>();
   805→          const unique: Value[] = [];
   806→          for (const item of args[0].val) {
   807→            const key = JSON.stringify(this.valueToJSON(item));
   808→            if (!seen.has(key)) {
