   851→  private readI32(actor: Actor): number {
   852→    const b0 = this.chunk.code[actor.ip++];
   853→    const b1 = this.chunk.code[actor.ip++];
   854→    const b2 = this.chunk.code[actor.ip++];
   855→    const b3 = this.chunk.code[actor.ip++];
   856→    return b0 | (b1 << 8) | (b2 << 16) | (b3 << 24);
   857→  }
   858→
   859→  private readF64(actor: Actor): number {
   860→    const buf = new ArrayBuffer(8);
   861→    const bytes = new Uint8Array(buf);
   862→    for (let i = 0; i < 8; i++) bytes[i] = this.chunk.code[actor.ip++];
   863→    return new Float64Array(buf)[0];
   864→  }
   865→
   866→  private valueToString(v: Value): string {
   867→    switch (v.tag) {
   868→      case "i32": case "f64": return String(v.val);
   869→      case "str": return v.val;
   870→      case "bool": return v.val ? "true" : "false";
   871→      case "void": return "void";
   872→      case "none": return "None";
   873→      case "arr": return `[${v.val.map((e) => this.valueToString(e)).join(", ")}]`;
   874→      case "struct": {
   875→        const entries = [...v.fields.entries()].map(([k, val]) => `${k}: ${this.valueToString(val)}`);
   876→        return `{ ${entries.join(", ")} }`;
   877→      }
   878→      case "ok": return `Ok(${this.valueToString(v.val)})`;
   879→      case "err": return `Err(${this.valueToString(v.val)})`;

