     8→
     9→trait Summary {
    10→    fn summarize() -> String;
    11→}
    12→
    13→// ============================================================
    14→// [Step 7 준비] 트레이트 2: 보안 레벨
    15→// ============================================================
    16→
    17→trait SecurityLevel {
    18→    fn level() -> u8;
    19→
    20→    fn is_critical() -> bool {
    21→        SecurityLevel::level() > 7
    22→    }
    23→}
    24→
    25→// ============================================================
    26→// [Step 6-7 기초] 트레이트 3: 전송 가능
    27→// ============================================================
    28→
    29→trait Transmittable {
    30→    fn serialize() -> String;
    31→    fn validate() -> bool;
    32→}
